import{_ as a,o,c as d,ag as e}from"./chunks/framework.ePeAWSvT.js";const r="/images/chatgpt-vs-claude-code.png",C=JSON.parse('{"title":"클로드코드란?","description":"","frontmatter":{},"headers":[],"relativePath":"학습자료/1-클로드코드란.md","filePath":"학습자료/1-클로드코드란.md"}'),s={name:"학습자료/1-클로드코드란.md"};function l(n,t,u,i,h,c){return o(),d("div",null,[...t[0]||(t[0]=[e(`<h1 id="클로드코드란" tabindex="-1">클로드코드란? <a class="header-anchor" href="#클로드코드란" aria-label="Permalink to &quot;클로드코드란?&quot;">​</a></h1><p>처음 들어보셨나요? 괜찮습니다. AI가 뭔지부터 차근차근 설명해 드릴게요.</p><hr><h2 id="ai가-뭔가요" tabindex="-1">AI가 뭔가요? <a class="header-anchor" href="#ai가-뭔가요" aria-label="Permalink to &quot;AI가 뭔가요?&quot;">​</a></h2><p><strong>인공지능(AI)</strong> 은 사람처럼 생각하고 대화할 수 있는 컴퓨터 프로그램입니다. 요즘 많이 들리는 ChatGPT, Gemini 같은 게 다 AI예요. 질문하면 답해주고, 글을 써주고, 요약도 해줍니다.</p><hr><h2 id="claude란" tabindex="-1">Claude란? <a class="header-anchor" href="#claude란" aria-label="Permalink to &quot;Claude란?&quot;">​</a></h2><p><strong>Claude(클로드)</strong> 는 <strong>Anthropic(앤트로픽)</strong> 이라는 미국 회사가 만든 AI입니다.</p><p>ChatGPT를 만든 OpenAI의 경쟁자라고 생각하시면 됩니다. 둘 다 &quot;대화형 AI&quot;인데, Claude만의 특징이 있습니다:</p><table tabindex="0"><thead><tr><th>특징</th><th>설명</th></tr></thead><tbody><tr><td><strong>긴 글 이해</strong></td><td>책 한 권 분량의 텍스트도 한 번에 읽고 분석</td></tr><tr><td><strong>안전성 중시</strong></td><td>&quot;해로운 답변을 안 하는 것&quot;에 특히 신경 씀</td></tr><tr><td><strong>자연스러운 한국어</strong></td><td>한국어 대화와 문서 작성 품질이 뛰어남</td></tr><tr><td><strong>코드 작성 능력</strong></td><td>프로그래밍 실력이 업계 최상위급</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Claude를 써보고 싶다면</p><p><a href="https://claude.ai" target="_blank" rel="noreferrer">claude.ai</a>에서 무료로 대화해볼 수 있습니다. ChatGPT처럼 웹 브라우저에서 채팅하는 방식이에요.</p></div><hr><h2 id="claude-code란" tabindex="-1">Claude Code란? <a class="header-anchor" href="#claude-code란" aria-label="Permalink to &quot;Claude Code란?&quot;">​</a></h2><blockquote><p><strong>Claude Code = Claude를 내 컴퓨터에서 직접 쓰는 도구</strong></p></blockquote><p>claude.ai에서 채팅하는 건 &quot;전화 상담&quot;이에요. 내 파일을 직접 보여줄 수 없고, 결과물도 복사-붙여넣기 해야 하죠.</p><p>Claude Code는 다릅니다. AI가 <strong>내 컴퓨터 안에 들어와서</strong> 직접 파일을 열고, 만들고, 수정합니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>채팅 AI (claude.ai, ChatGPT)</span></span>
<span class="line"><span>  → &quot;이거 해줘&quot; → 결과를 복붙 → 내가 직접 적용</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude Code</span></span>
<span class="line"><span>  → &quot;이거 해줘&quot; → AI가 직접 파일을 만들고 수정 → 끝!</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">한마디로</p><p><strong>&quot;복붙 없이, 매번 새로 설명 없이, AI가 내 컴퓨터에서 알아서 해주는 경험&quot;</strong> 이 Claude Code입니다.</p></div><hr><h2 id="claude-vs-claude-code-차이" tabindex="-1">Claude vs Claude Code 차이 <a class="header-anchor" href="#claude-vs-claude-code-차이" aria-label="Permalink to &quot;Claude vs Claude Code 차이&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Claude (웹)</th><th>Claude Code</th></tr></thead><tbody><tr><td><strong>어디서?</strong></td><td>웹 브라우저 (claude.ai)</td><td>내 컴퓨터 (VS Code / 터미널)</td></tr><tr><td><strong>뭘 하나?</strong></td><td>대화, 질문 답변, 글쓰기</td><td>내 파일을 직접 읽고, 만들고, 수정</td></tr><tr><td><strong>비유하면</strong></td><td>전화 상담사</td><td>옆자리 동료</td></tr><tr><td><strong>파일 접근</strong></td><td>대화창에 복붙해야 함</td><td>내 폴더를 직접 봄</td></tr><tr><td><strong>자동화</strong></td><td>매번 새로 요청해야 함</td><td><strong>스킬</strong>로 반복 실행 가능</td></tr><tr><td><strong>외부 연결</strong></td><td>제한적</td><td><strong>MCP</strong>로 캘린더, DB 등 연결</td></tr><tr><td><strong>기억</strong></td><td>대화 끝나면 리셋</td><td><strong>CLAUDE.md</strong>로 영구 기억</td></tr></tbody></table><p><img src="`+r+'" alt="ChatGPT는 전화 상담사, Claude Code는 옆자리 동료"></p><div class="info custom-block"><p class="custom-block-title">좀 더 생생하게 비유해 볼게요</p><p><strong>Claude (웹) = 전화 상담사</strong> 전화로 &quot;제 냉장고 안에 뭐가 있는지 알려줘&quot;라고 물어봐도, 상담사는 여러분 집 냉장고를 볼 수가 없죠. 여러분이 직접 냉장고 문을 열어서 &quot;달걀 3개, 우유 1개…&quot; 읽어줘야 합니다.</p><p><strong>Claude Code = 옆자리 동료</strong> &quot;냉장고 좀 봐줄 수 있어?&quot;라고 하면, 동료가 직접 냉장고 문을 열고 확인해 줍니다. 필요하면 장볼 목록도 바로 작성해 주고, 내일 일정과 비교해서 &quot;이번 주 저녁은 이걸로 하면 어때요?&quot;까지 제안해 줍니다.</p></div><hr><h2 id="비슷한-서비스-비교" tabindex="-1">비슷한 서비스 비교 <a class="header-anchor" href="#비슷한-서비스-비교" aria-label="Permalink to &quot;비슷한 서비스 비교&quot;">​</a></h2><p>&quot;이런 AI 코딩 도구가 Claude Code만 있는 건 아니잖아요?&quot; 맞습니다. 간단히 비교해볼게요.</p><table tabindex="0"><thead><tr><th>서비스</th><th>만든 곳</th><th>특징</th><th>가격</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td>Anthropic</td><td>스킬(자동화), CLAUDE.md(기억), MCP(외부연결)</td><td>Pro $20/월</td></tr><tr><td><strong>ChatGPT</strong></td><td>OpenAI</td><td>가장 유명한 AI. 웹 채팅 중심</td><td>Plus $20/월</td></tr><tr><td><strong>GitHub Copilot</strong></td><td>Microsoft</td><td>코드 자동완성 특화. 개발자 도구</td><td>$10/월~</td></tr><tr><td><strong>Cursor</strong></td><td>Cursor Inc.</td><td>VS Code 기반 AI 코드 편집기</td><td>$20/월~</td></tr><tr><td><strong>Windsurf</strong></td><td>Codeium</td><td>AI 코딩 에디터. Cursor 대안</td><td>$15/월~</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">비개발자에게는?</p><p>GitHub Copilot, Cursor, Windsurf는 <strong>개발자 특화</strong> 도구입니다. 비개발자가 업무 자동화 목적으로 쓰기에는 <strong>Claude Code가 가장 접근하기 쉽습니다.</strong> 스킬을 글로 적으면 되니까요 — 코드를 몰라도 됩니다.</p></div><hr><h2 id="왜-claude-code인가" tabindex="-1">왜 Claude Code인가? <a class="header-anchor" href="#왜-claude-code인가" aria-label="Permalink to &quot;왜 Claude Code인가?&quot;">​</a></h2><p>Claude Code만의 3가지 무기가 있습니다. 오늘 워크샵에서 이것들을 하나씩 배웁니다.</p><h3 id="_1-스킬-skills-—-반복-업무-자동화" tabindex="-1">1. 스킬 (Skills) — 반복 업무 자동화 <a class="header-anchor" href="#_1-스킬-skills-—-반복-업무-자동화" aria-label="Permalink to &quot;1. 스킬 (Skills) — 반복 업무 자동화&quot;">​</a></h3><blockquote><p>&quot;한 번 만들면 <code>/스킬이름</code> 한 줄로 매번 재사용&quot;</p></blockquote><p>매주 같은 형식의 보고서, 매번 비슷한 이메일... 스킬로 만들면 1분이면 끝납니다.</p><h3 id="_2-claude-md-—-ai의-기억" tabindex="-1">2. CLAUDE.md — AI의 기억 <a class="header-anchor" href="#_2-claude-md-—-ai의-기억" aria-label="Permalink to &quot;2. CLAUDE.md — AI의 기억&quot;">​</a></h3><blockquote><p>&quot;한 번 알려주면 매번 기억&quot;</p></blockquote><p>&quot;한국어로, 존댓말로, 보고서 형식은 이거로...&quot; 매번 설명할 필요 없습니다.</p><h3 id="_3-mcp-—-외부-도구-연결" tabindex="-1">3. MCP — 외부 도구 연결 <a class="header-anchor" href="#_3-mcp-—-외부-도구-연결" aria-label="Permalink to &quot;3. MCP — 외부 도구 연결&quot;">​</a></h3><blockquote><p>&quot;캘린더, 노션, 슬랙까지 AI가 직접 조작&quot;</p></blockquote><p>&quot;내일 일정 잡아줘&quot;가 실제로 Google Calendar에 반영됩니다.</p><div class="tip custom-block"><p class="custom-block-title">성장 순서</p><p><strong>스킬 → CLAUDE.md → MCP</strong></p><p>오늘은 스킬에 집중합니다. 나머지는 스킬을 마스터한 뒤 자연스럽게 배우게 됩니다.</p></div><hr><h2 id="무엇을-할-수-있나요" tabindex="-1">무엇을 할 수 있나요? <a class="header-anchor" href="#무엇을-할-수-있나요" aria-label="Permalink to &quot;무엇을 할 수 있나요?&quot;">​</a></h2><p>실제 상황으로 보여드릴게요.</p><h3 id="before-after" tabindex="-1">Before / After <a class="header-anchor" href="#before-after" aria-label="Permalink to &quot;Before / After&quot;">​</a></h3><p><strong>상황 1: 거래처 이메일 작성</strong></p><table tabindex="0"><thead><tr><th>Before (기존 방식)</th><th>After (Claude Code)</th></tr></thead><tbody><tr><td>ChatGPT 열기 → 상황 설명 → 초안 복사 → 이메일 앱에 붙여넣기</td><td>&quot;거래처에 납품 일정 변경 이메일 써줘&quot; → 파일로 바로 저장</td></tr></tbody></table><p><strong>상황 2: 회의록 정리</strong></p><table tabindex="0"><thead><tr><th>Before (기존 방식)</th><th>After (Claude Code)</th></tr></thead><tbody><tr><td>회의록 복사 → ChatGPT에 붙여넣기 → 요약 복사 → 문서에 붙여넣기</td><td>&quot;회의록 요약해줘&quot; → 요약본 파일 자동 생성</td></tr></tbody></table><p><strong>상황 3: 반복 업무 자동화</strong></p><table tabindex="0"><thead><tr><th>Before (기존 방식)</th><th>After (Claude Code)</th></tr></thead><tbody><tr><td>매주 월요일마다 같은 내용을 처음부터 다시 입력</td><td>스킬 한 번 만들어두면 <code>/주간보고</code> 한 줄로 끝</td></tr></tbody></table><details class="details custom-block"><summary>개발자가 아닌데 써도 될까요?</summary><p>물론입니다! Claude Code는 원래 개발자용으로 만들어졌지만, 문서 작업, 데이터 정리, 이메일 작성, 일정 관리 같은 일반 업무에도 매우 유용합니다. 오늘 워크샵이 바로 그 사례를 보여드리기 위해 준비됐습니다.</p></details><hr><h2 id="어떻게-생겼나요" tabindex="-1">어떻게 생겼나요? <a class="header-anchor" href="#어떻게-생겼나요" aria-label="Permalink to &quot;어떻게 생겼나요?&quot;">​</a></h2><p>Claude Code는 두 가지 방식으로 사용합니다.</p><p><strong>VS Code 안에서 사용할 때</strong></p><p>VS Code(코드 편집기) 왼쪽 사이드바에 Claude 아이콘이 생깁니다. 클릭하면 채팅창이 열리고, 거기서 AI에게 지시를 내리면 됩니다. AI는 현재 열려 있는 폴더의 파일들을 직접 보고 수정합니다.</p><p><strong>터미널에서 사용할 때</strong></p><p>터미널(검은 화면의 명령어 입력창)에서 <code>claude</code> 라고 입력하면 Claude Code가 실행됩니다. 마찬가지로 채팅 형식으로 대화하면 됩니다.</p><div class="tip custom-block"><p class="custom-block-title">터미널이 낯설어도 괜찮아요</p><p>오늘 워크샵에서는 VS Code 사이드바 방식을 주로 사용합니다. 터미널을 몰라도 충분히 따라올 수 있습니다.</p></div><hr><h2 id="핵심-정리" tabindex="-1">핵심 정리 <a class="header-anchor" href="#핵심-정리" aria-label="Permalink to &quot;핵심 정리&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">기억하세요</p><ul><li><strong>AI</strong> = 사람처럼 대화하는 컴퓨터 프로그램</li><li><strong>Claude</strong> = Anthropic이 만든 AI (ChatGPT의 경쟁자)</li><li><strong>Claude Code</strong> = Claude를 내 컴퓨터에서 직접 쓰는 도구</li></ul><p><strong>대화형 AI</strong> + <strong>내 컴퓨터 접근</strong> + <strong>자동화</strong> = Claude Code</p><p>ChatGPT가 &quot;말로 도와주는 AI&quot;라면, Claude Code는 &quot;손발이 있는 AI&quot;입니다.</p></div><hr><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이제 Claude Code가 뭔지 감이 오셨나요?</p><p>다음 페이지에서는 Claude Code의 핵심 기능인 <strong>스킬</strong>을 자세히 배웁니다.</p><p><strong><a href="/학습자료/2-스킬개념/2-1-스킬이란">스킬이란? →</a></strong></p>',68)])])}const g=a(s,[["render",l]]);export{C as __pageData,g as default};
